  url: string;
  createdAt: string;

  // Permissões
  targetAudience: TargetAudience;
  scope: Scope;
  poloId?: string; // Se scope == POLO_ESPECIFICO
  poloName?: string;

  // Metadados
  authorId: string;
  authorName: string;
  isTeacherUpload: boolean; // Se true, foi um professor que subiu para a biblioteca dele
