export const bibliotecaService = {
  async getInstitutionalDocuments() {
    return new Promise<LibraryDocument[]>((resolve) => {
      setTimeout(() => resolve(mockDocs), 500);
    });
  },

  async getTeacherRepositories() {
    return new Promise<TeacherRepository[]>((resolve) => {
      setTimeout(() => resolve(mockTeachers), 500);
    });
  },

  async uploadDocument(doc: Omit<LibraryDocument, 'id' | 'createdAt' | 'authorId' | 'authorName' | 'isTeacherUpload'>) {
    return new Promise<void>((resolve) => {
      setTimeout(() => {
        const newDoc: LibraryDocument = {
          ...doc,
          id: Math.random().toString(36).substr(2, 9),
          createdAt: new Date().toISOString().split('T')[0],
          authorId: 'gestor',
          authorName: 'Gestor Logado',
          isTeacherUpload: false
        };
        mockDocs.unshift(newDoc);
        resolve();
      }, 800);
    });
  },

  async deleteDocument(id: string) {
    return new Promise<void>((resolve) => {
        setTimeout(() => {
            mockDocs = mockDocs.filter(d => d.id !== id);
            resolve();
        }, 500);
    });
  }
};

import React, { useState, useEffect } from 'react';
import { X, Upload, Globe, MapPin, Users, Lock, FileText, Check } from 'lucide-react';
import { TargetAudience, Scope } from '../biblioteca.types';
import { empresasService } from '../../configuracoes/empresas/empresas.service';

interface UploadModalProps {
  isOpen: boolean;
  onClose: () => void;
  onUpload: (data: any) => void;
}

const UploadModal: React.FC<UploadModalProps> = ({ isOpen, onClose, onUpload }) => {
  const [polos, setPolos] = useState<any[]>([]);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    targetAudience: 'ALUNOS' as TargetAudience,
    scope: 'GLOBAL' as Scope,
    poloId: '',
    file: null as File | null
  });

  useEffect(() => {
    empresasService.getAll().then(setPolos);
  }, []);

  if (!isOpen) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFormData({ ...formData, file: e.target.files[0] });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.file) {
        alert("Selecione um arquivo.");
        return;
    }

    // Preparar payload
    const poloSelected = polos.find(p => p.id === formData.poloId);

    // Simula tamanho e tipo
    const sizeMB = (formData.file.size / (1024 * 1024)).toFixed(2);
    const ext = formData.file.name.split('.').pop()?.toUpperCase() || 'OTHER';
    let fileType = 'OTHER';
    if(['PDF'].includes(ext)) fileType = 'PDF';
    if(['DOC', 'DOCX'].includes(ext)) fileType = 'DOC';
    if(['XLS', 'XLSX'].includes(ext)) fileType = 'XLS';
    if(['JPG', 'PNG', 'JPEG'].includes(ext)) fileType = 'IMG';

    onUpload({
        title: formData.title,
        description: formData.description,
        fileType,
        size: sizeMB + ' MB',
        url: '#', // Em produção seria a URL do Storage
        targetAudience: formData.targetAudience,
        scope: formData.scope,
        poloId: formData.scope === 'GLOBAL' ? undefined : formData.poloId,
        poloName: formData.scope === 'GLOBAL' ? undefined : poloSelected?.nomeFantasia
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-[#001a33]/60 backdrop-blur-sm transition-opacity" onClick={onClose}></div>

      <div className="relative bg-white rounded-[2rem] w-full max-w-2xl p-8 shadow-2xl animate-fadeIn border border-slate-100 max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-6 pb-4 border-b border-slate-100">
          <div>
             <h3 className="text-xl font-black text-[#001a33] uppercase tracking-tight">Publicar Documento</h3>
             <p className="text-xs text-slate-500 font-medium">Adicione arquivos ao acervo institucional.</p>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-50 text-slate-400 hover:text-red-500 transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">

          {/* Área de Upload */}
          <div className="relative group">
            <input 
                type="file" 
                id="file-upload" 
                className="hidden" 
                onChange={handleFileChange}
            />
            <label 
                htmlFor="file-upload"
                className={`w-full h-32 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center cursor-pointer transition-all ${
                    formData.file 
                    ? 'border-emerald-300 bg-emerald-50' 
                    : 'border-slate-300 bg-slate-50 hover:bg-blue-50 hover:border-blue-400'
                }`}
            >
                {formData.file ? (
                    <>
                        <div className="w-10 h-10 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-2">
                            <Check size={20} />
                        </div>
                        <p className="text-sm font-bold text-emerald-800">{formData.file.name}</p>
                        <p className="text-xs text-emerald-600">Clique para trocar</p>
                    </>
                ) : (
                    <>
                        <div className="w-10 h-10 bg-white text-slate-400 rounded-full flex items-center justify-center mb-2 shadow-sm group-hover:text-blue-500 transition-colors">
                            <Upload size={20} />
                        </div>
                        <p className="text-sm font-bold text-slate-600 group-hover:text-blue-700">Clique para selecionar o arquivo</p>
                        <p className="text-[10px] text-slate-400">PDF, DOCX, XLS, JPG (Máx 10MB)</p>
                    </>
                )}
            </label>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2 space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Título do Documento</label>
                <input 
                    type="text" 
                    className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-blue-500 text-slate-700"
                    placeholder="Ex: Calendário Acadêmico 2024"
                    value={formData.title}
                    onChange={(e) => setFormData({...formData, title: e.target.value})}
                    required
                />
            </div>
            <div className="md:col-span-2 space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Descrição (Opcional)</label>
                <input 
                    type="text" 
                    className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-blue-500 text-slate-700"
                    placeholder="Breve descrição do conteúdo"
                    value={formData.description}
                    onChange={(e) => setFormData({...formData, description: e.target.value})}
                />
            </div>
          </div>

          <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-4">
             <div className="flex items-center gap-2 text-blue-600 mb-2">
                <Lock size={16} />
                <h4 className="text-xs font-black uppercase tracking-wider">Permissões de Acesso</h4>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-1">
                        <Users size={12} /> Público Alvo
                    </label>
                    <select 
                        className="w-full px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm outline-none focus:border-blue-500 cursor-pointer"
                        value={formData.targetAudience}
                        onChange={(e) => setFormData({...formData, targetAudience: e.target.value as TargetAudience})}
                    >
                        <option value="ALUNOS">Somente Alunos</option>
                        <option value="PROFESSORES">Somente Professores</option>
                        <option value="INTERNO">Somente Interno (Gestão)</option>
                        <option value="TODOS">Público (Todos)</option>
                    </select>
                </div>

                <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-1">
                        <Globe size={12} /> Abrangência
                    </label>
                    <select 
                        className="w-full px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm outline-none focus:border-blue-500 cursor-pointer"
                        value={formData.scope}
                        onChange={(e) => setFormData({...formData, scope: e.target.value as Scope, poloId: ''})}
                    >
                        <option value="GLOBAL">Global (Todos os Polos)</option>
                        <option value="POLO_ESPECIFICO">Polo Específico</option>
                    </select>
                </div>

                {formData.scope === 'POLO_ESPECIFICO' && (
                    <div className="md:col-span-2 space-y-2 animate-fadeIn">
                        <label className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-1">
                            <MapPin size={12} /> Selecione o Polo
                        </label>
                        <select 
                            className="w-full px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm outline-none focus:border-blue-500 cursor-pointer"
                            value={formData.poloId}
                            onChange={(e) => setFormData({...formData, poloId: e.target.value})}
                            required
                        >
                            <option value="">-- Selecione --</option>
                            {polos.map(p => (
                                <option key={p.id} value={p.id}>{p.nomeFantasia} ({p.cidade})</option>
                            ))}
                        </select>
                    </div>
                )}
             </div>
          </div>

          <div className="flex justify-end pt-4">
            <button 
                type="submit"
                className="px-8 py-3 bg-[#001a33] text-white rounded-xl font-bold uppercase text-xs tracking-wider hover:bg-blue-900 transition-colors shadow-lg flex items-center gap-2"
            >
                <Upload size={16} /> Publicar Documento
            </button>
          </div>

        </form>
      </div>
    </div>
  );
};

export default UploadModal;

import React, { useState, useEffect } from 'react';
import { FileText, Download, Trash2, Globe, MapPin, Lock, Users, Briefcase } from 'lucide-react';
import { LibraryDocument } from '../biblioteca.types';
import { bibliotecaService } from '../biblioteca.service';

interface InstitutionalLibraryProps {
  searchTerm: string;
  refreshTrigger: number;
}

const InstitutionalLibrary: React.FC<InstitutionalLibraryProps> = ({ searchTerm, refreshTrigger }) => {
  const [documents, setDocuments] = useState<LibraryDocument[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadDocs();
  }, [refreshTrigger]);

  const loadDocs = async () => {
    setLoading(true);
    const data = await bibliotecaService.getInstitutionalDocuments();
    setDocuments(data);
    setLoading(false);
  };

  const handleDelete = async (id: string) => {
    if (confirm('Tem certeza que deseja remover este documento?')) {
        await bibliotecaService.deleteDocument(id);
        loadDocs();
    }
  };

  const filteredDocs = documents.filter(doc => 
    doc.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    doc.description?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getFileIcon = (type: string) => {
    switch(type) {
        case 'PDF': return <div className="w-10 h-10 rounded-lg bg-red-50 text-red-600 flex items-center justify-center font-bold text-xs border border-red-100">PDF</div>;
        case 'DOC': return <div className="w-10 h-10 rounded-lg bg-blue-50 text-blue-600 flex items-center justify-center font-bold text-xs border border-blue-100">DOC</div>;
        case 'XLS': return <div className="w-10 h-10 rounded-lg bg-emerald-50 text-emerald-600 flex items-center justify-center font-bold text-xs border border-emerald-100">XLS</div>;
        default: return <div className="w-10 h-10 rounded-lg bg-slate-50 text-slate-600 flex items-center justify-center font-bold text-xs border border-slate-100">FILE</div>;
    }
  };

  const getAudienceBadge = (audience: string) => {
    switch(audience) {
        case 'ALUNOS': return <span className="flex items-center gap-1 bg-cyan-50 text-cyan-700 px-2 py-0.5 rounded text-[10px] font-bold uppercase border border-cyan-100"><Users size={10} /> Alunos</span>;
        case 'PROFESSORES': return <span className="flex items-center gap-1 bg-purple-50 text-purple-700 px-2 py-0.5 rounded text-[10px] font-bold uppercase border border-purple-100"><Briefcase size={10} /> Profs</span>;
        case 'INTERNO': return <span className="flex items-center gap-1 bg-slate-100 text-slate-600 px-2 py-0.5 rounded text-[10px] font-bold uppercase border border-slate-200"><Lock size={10} /> Interno</span>;
        default: return <span className="flex items-center gap-1 bg-blue-50 text-blue-700 px-2 py-0.5 rounded text-[10px] font-bold uppercase border border-blue-100"><Globe size={10} /> Público</span>;
    }
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Carregando acervo...</div>;

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fadeIn">
      {filteredDocs.length === 0 ? (
        <div className="col-span-full py-16 text-center bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200">
            <FileText className="mx-auto text-slate-300 mb-4" size={48} />
            <p className="text-slate-500 font-medium">Nenhum documento encontrado.</p>
        </div>
      ) : (
        filteredDocs.map((doc) => (
            <div key={doc.id} className="bg-white rounded-3xl border border-slate-100 p-5 hover:shadow-xl hover:shadow-blue-900/5 transition-all duration-300 group flex flex-col justify-between h-full relative overflow-hidden">

                {/* Header Card */}
                <div className="flex justify-between items-start mb-4">
                    {getFileIcon(doc.fileType)}
                    <div className="flex flex-col items-end gap-1">
                        {getAudienceBadge(doc.targetAudience)}
                        {doc.scope === 'GLOBAL' ? (
                            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-wider flex items-center gap-1">
                                <Globe size={10} /> Global
                            </span>
                        ) : (
                            <span className="text-[9px] text-orange-500 font-bold uppercase tracking-wider flex items-center gap-1 bg-orange-50 px-1.5 py-0.5 rounded">
                                <MapPin size={10} /> {doc.poloName}
                            </span>
                        )}
                    </div>
                </div>

                {/* Content */}
                <div className="mb-6">
                    <h4 className="font-bold text-[#001a33] text-sm leading-snug mb-2 line-clamp-2" title={doc.title}>
                        {doc.title}
                    </h4>
                    <p className="text-xs text-slate-500 line-clamp-2 min-h-[2.5em]">
                        {doc.description || 'Sem descrição.'}
                    </p>
                </div>

                {/* Footer */}
                <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <div className="text-[10px] text-slate-400 font-medium">
                        {new Date(doc.createdAt).toLocaleDateString('pt-BR')} • {doc.size}
                    </div>
                    <div className="flex gap-1">
                        <button className="p-2 rounded-lg text-slate-400 hover:text-blue-600 hover:bg-blue-50 transition-colors" title="Baixar">
                            <Download size={16} />
                        </button>
                        <button 
                            onClick={() => handleDelete(doc.id)}
                            className="p-2 rounded-lg text-slate-400 hover:text-red-500 hover:bg-red-50 transition-colors" 
                            title="Excluir"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </div>
            </div>
        ))
      )}
    </div>
  );
};

export default InstitutionalLibrary;

