export type EventType = 'INSTITUCIONAL' | 'PEDAGOGICO' | 'FERIADO' | 'FINANCEIRO' | 'EVENTO';

export interface CalendarEvent {
  id: string;
  title: string;
  description?: string;
  date: string; // YYYY-MM-DD
  type: EventType;
  color: string; // Hex code
}

export const EVENT_COLORS = {
  INSTITUCIONAL: { label: 'Institucional', color: '#001a33', bg: 'bg-[#001a33]' }, // Azul Escuro
  PEDAGOGICO: { label: 'Pedagógico', color: '#059669', bg: 'bg-emerald-600' }, // Verde
  FERIADO: { label: 'Feriado/Recesso', color: '#dc2626', bg: 'bg-red-600' }, // Vermelho
  FINANCEIRO: { label: 'Financeiro', color: '#7c3aed', bg: 'bg-violet-600' }, // Roxo
  EVENTO: { label: 'Eventos', color: '#d97706', bg: 'bg-amber-600' }, // Laranja
};

import { CalendarEvent } from './calendario.types';

let mockEvents: CalendarEvent[] = [
  {
    id: '1',
    title: 'Início das Aulas',
    description: 'Boas vindas aos alunos veteranos e calouros.',
    date: new Date().toISOString().split('T')[0], // Hoje
    type: 'PEDAGOGICO',
    color: '#059669'
  },
  {
    id: '2',
    title: 'Reunião de Pais',
    description: 'Apresentação do semestre letivo.',
    date: '2024-03-10',
    type: 'INSTITUCIONAL',
    color: '#001a33'
  },
  {
    id: '3',
    title: 'Vencimento Mensalidade',
    description: 'Data limite sem juros.',
    date: '2024-03-05',
    type: 'FINANCEIRO',
    color: '#7c3aed'
  }
];

export const calendarioService = {
  async getEvents() {
    return new Promise<CalendarEvent[]>((resolve) => {
      setTimeout(() => resolve(mockEvents), 300);
    });
  },

  async addEvent(event: Omit<CalendarEvent, 'id'>) {
    return new Promise<CalendarEvent>((resolve) => {
      setTimeout(() => {
        const newEvent = { ...event, id: Math.random().toString(36).substr(2, 9) };
        mockEvents.push(newEvent);
        resolve(newEvent);
      }, 300);
    });
  },

  async deleteEvent(id: string) {
    return new Promise<void>((resolve) => {
        setTimeout(() => {
            mockEvents = mockEvents.filter(e => e.id !== id);
            resolve();
        }, 300);
    });
  }
};

import React, { useState } from 'react';
import { X, Calendar, AlignLeft, Trash2, Plus } from 'lucide-react';
import { CalendarEvent, EVENT_COLORS, EventType } from '../calendario.types';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedDate: Date;
  eventsOnDate: CalendarEvent[];
  onAddEvent: (event: any) => void;
  onDeleteEvent: (id: string) => void;
}

const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, onClose, selectedDate, eventsOnDate, onAddEvent, onDeleteEvent 
}) => {
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    type: 'INSTITUCIONAL' as EventType
  });

  if (!isOpen) return null;

  // Formata a data para YYYY-MM-DD para salvar
  const dateStr = selectedDate.toISOString().split('T')[0];

  // Formata para exibição
  const displayDate = selectedDate.toLocaleDateString('pt-BR', { 
    weekday: 'long', day: 'numeric', month: 'long' 
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title) return;

    onAddEvent({
      ...formData,
      date: dateStr,
      color: EVENT_COLORS[formData.type].color
    });

    // Reset
    setFormData({ title: '', description: '', type: 'INSTITUCIONAL' });
    setShowForm(false);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-[#001a33]/60 backdrop-blur-sm transition-opacity" onClick={onClose}></div>

      <div className="relative bg-white rounded-[2rem] w-full max-w-md p-6 shadow-2xl animate-fadeIn border border-slate-100 flex flex-col max-h-[85vh]">

        {/* Header */}
        <div className="flex justify-between items-center mb-6 pb-4 border-b border-slate-100">
          <div>
             <h3 className="text-xl font-black text-[#001a33] uppercase tracking-tight capitalize">
               {displayDate}
             </h3>
             <p className="text-xs text-slate-500 font-medium">Gerenciar observações desta data.</p>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-50 text-slate-400 hover:text-red-500 transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Lista de Eventos Existentes */}
        <div className="flex-1 overflow-y-auto mb-4 space-y-3 custom-scrollbar">
          {eventsOnDate.length === 0 && !showForm && (
            <div className="text-center py-8 text-slate-400 text-sm bg-slate-50 rounded-2xl border border-dashed border-slate-200">
              Nenhuma observação para este dia.
            </div>
          )}

          {eventsOnDate.map(event => (
            <div key={event.id} className="p-4 rounded-xl border border-slate-100 bg-white shadow-sm flex items-start gap-3 group hover:border-slate-300 transition-all">
              <div 
                className="w-3 h-3 rounded-full mt-1.5 shrink-0" 
                style={{ backgroundColor: event.color }} 
              />
              <div className="flex-1">
                <h4 className="text-sm font-bold text-[#001a33]">{event.title}</h4>
                <p className="text-xs text-slate-500 mt-1">{event.description || 'Sem descrição'}</p>
                <span className="inline-block mt-2 text-[9px] font-bold uppercase tracking-wider text-slate-400 bg-slate-50 px-2 py-0.5 rounded">
                  {EVENT_COLORS[event.type]?.label || event.type}
                </span>
              </div>
              <button 
                onClick={() => onDeleteEvent(event.id)}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 hover:text-red-500 transition-all"
              >
                <Trash2 size={16} />
              </button>
            </div>
          ))}
        </div>

        {/* Formulário de Adição */}
        {showForm ? (
          <form onSubmit={handleSubmit} className="bg-slate-50 p-4 rounded-2xl border border-slate-200 animate-fadeIn">
            <div className="space-y-3">
              <input 
                type="text" 
                placeholder="Título da Observação"
                className="w-full px-3 py-2 rounded-xl border border-slate-200 text-sm font-bold text-[#001a33] outline-none focus:border-blue-500"
                value={formData.title}
                onChange={(e) => setFormData({...formData, title: e.target.value})}
                autoFocus
                required
              />
              <textarea 
                placeholder="Detalhes adicionais..."
                className="w-full px-3 py-2 rounded-xl border border-slate-200 text-sm text-slate-600 outline-none focus:border-blue-500 resize-none h-20"
                value={formData.description}
                onChange={(e) => setFormData({...formData, description: e.target.value})}
              />

              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 uppercase">Categoria / Cor</label>
                <div className="flex flex-wrap gap-2">
                  {(Object.keys(EVENT_COLORS) as EventType[]).map((type) => (
                    <button
                      key={type}
                      type="button"
                      onClick={() => setFormData({...formData, type})}
                      className={`px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all border ${
                        formData.type === type 
                          ? 'border-transparent text-white shadow-md transform scale-105' 
                          : 'border-slate-200 bg-white text-slate-500 hover:bg-slate-100'
                      }`}
                      style={{ backgroundColor: formData.type === type ? EVENT_COLORS[type].color : undefined }}
                    >
                      {EVENT_COLORS[type].label}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex justify-end gap-2 pt-2">
                <button 
                  type="button" 
                  onClick={() => setShowForm(false)}
                  className="px-4 py-2 rounded-lg text-xs font-bold text-slate-500 hover:bg-slate-200 transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className="px-4 py-2 rounded-lg bg-[#001a33] text-white text-xs font-bold uppercase tracking-wider hover:bg-blue-900 transition-colors shadow-lg"
                >
                  Salvar
                </button>
              </div>
            </div>
          </form>
        ) : (
          <button 
            onClick={() => setShowForm(true)}
            className="w-full py-3 bg-[#001a33] text-white rounded-xl font-bold uppercase text-xs tracking-wider hover:bg-blue-900 transition-colors shadow-lg flex items-center justify-center gap-2"
          >
            <Plus size={16} /> Adicionar Observação
          </button>
        )}

      </div>
    </div>
  );
};

