import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, Info } from 'lucide-react';
import { calendarioService } from './calendario.service';
import { CalendarEvent, EVENT_COLORS } from './calendario.types';
import EventModal from './components/EventModal';

const CalendarioPage: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    loadEvents();
  }, []);

  const loadEvents = async () => {
    const data = await calendarioService.getEvents();
    setEvents(data);
  };

  const handleAddEvent = async (event: any) => {
    await calendarioService.addEvent(event);
    loadEvents();
  };

  const handleDeleteEvent = async (id: string) => {
    await calendarioService.deleteEvent(id);
    loadEvents();
  };

  // Navegação
  const prevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const nextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  const goToToday = () => {
    setCurrentDate(new Date());
  };

  // Lógica de Renderização do Calendário
  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const firstDayOfWeek = new Date(year, month, 1).getDay(); // 0 = Domingo

    const days = [];

    // Padding para dias do mês anterior
    for (let i = 0; i < firstDayOfWeek; i++) {
      days.push(null);
    }

    // Dias do mês atual
    for (let i = 1; i <= daysInMonth; i++) {
      days.push(new Date(year, month, i));
    }

    return days;
  };

  const days = getDaysInMonth(currentDate);
  const monthName = currentDate.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

  const getEventsForDay = (date: Date) => {
    const dateStr = date.toISOString().split('T')[0];
    return events.filter(e => e.date === dateStr);
  };

  const handleDayClick = (date: Date) => {
    setSelectedDate(date);
    setIsModalOpen(true);
  };

  return (
    <div className="max-w-7xl mx-auto animate-fadeIn min-h-screen pb-10">

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-6">
        <div>
          <h2 className="text-3xl font-black text-[#001a33] uppercase tracking-tight flex items-center gap-3">
            <CalendarIcon className="text-blue-600" size={32} />
            Calendário Acadêmico
          </h2>
          <p className="text-slate-500 font-medium mt-1">Gerencie eventos, feriados e datas importantes.</p>
        </div>

        <div className="flex items-center gap-4 bg-white p-2 rounded-2xl shadow-sm border border-slate-100">
          <button onClick={prevMonth} className="p-3 hover:bg-slate-50 rounded-xl text-slate-500 hover:text-[#001a33] transition-colors">
            <ChevronLeft size={20} />
          </button>
          <div className="text-center min-w-[180px]">
            <h3 className="text-lg font-black text-[#001a33] uppercase tracking-wide">{monthName}</h3>
          </div>
          <button onClick={nextMonth} className="p-3 hover:bg-slate-50 rounded-xl text-slate-500 hover:text-[#001a33] transition-colors">
            <ChevronRight size={20} />
          </button>
          <div className="w-px h-8 bg-slate-200 mx-2"></div>
          <button onClick={goToToday} className="px-4 py-2 bg-slate-100 text-slate-600 text-xs font-bold uppercase tracking-wider rounded-xl hover:bg-slate-200 transition-colors">
            Hoje
          </button>
        </div>
      </div>

      {/* Legenda */}
      <div className="flex flex-wrap gap-4 mb-6 px-4">
        {Object.values(EVENT_COLORS).map((ec, idx) => (
          <div key={idx} className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full" style={{ backgroundColor: ec.color }}></div>
            <span className="text-xs font-bold text-slate-500 uppercase tracking-wide">{ec.label}</span>
          </div>
        ))}
      </div>

      {/* Grid do Calendário */}
      <div className="bg-white rounded-[2.5rem] shadow-xl border border-slate-100 overflow-hidden">

        {/* Dias da Semana */}
        <div className="grid grid-cols-7 bg-slate-50 border-b border-slate-100">
          {['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'].map(day => (
            <div key={day} className="py-4 text-center text-xs font-black text-slate-400 uppercase tracking-widest">
              {day}
            </div>
          ))}
        </div>

        {/* Dias */}
        <div className="grid grid-cols-7 auto-rows-fr">
          {days.map((date, idx) => {
            if (!date) return <div key={idx} className="bg-slate-50/30 border-b border-r border-slate-50 min-h-[120px]"></div>;

            const dayEvents = getEventsForDay(date);
            const isToday = new Date().toDateString() === date.toDateString();

            return (
              <div 
                key={idx} 
                onClick={() => handleDayClick(date)}
                className={`min-h-[120px] p-2 border-b border-r border-slate-100 hover:bg-blue-50/30 transition-colors cursor-pointer group flex flex-col relative ${isToday ? 'bg-blue-50/20' : ''}`}
              >
                <div className={`w-8 h-8 flex items-center justify-center rounded-full text-sm font-bold mb-2 ${
                  isToday ? 'bg-[#4169E1] text-white shadow-lg shadow-blue-500/30' : 'text-slate-500 group-hover:text-[#001a33]'
                }`}>
                  {date.getDate()}
                </div>

                {/* Eventos no dia */}
                <div className="flex-1 flex flex-col gap-1 overflow-hidden">
                  {dayEvents.map(event => (
                    <div 
                      key={event.id}
                      className="px-2 py-1 rounded-md text-[9px] font-bold text-white truncate shadow-sm"
                      style={{ backgroundColor: event.color }}
                      title={event.title}
                    >
                      {event.title}
                    </div>
                  ))}
                </div>

                {/* Botão de Adicionar (+) no Hover */}
                <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                   <div className="w-6 h-6 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center hover:bg-blue-100 hover:text-blue-600">
                     <PlusIcon size={12} />
                   </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {selectedDate && (
        <EventModal 
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          selectedDate={selectedDate}
          eventsOnDate={getEventsForDay(selectedDate)}
          onAddEvent={handleAddEvent}
          onDeleteEvent={handleDeleteEvent}
        />
      )}

    </div>
  );
};

