import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, Filter } from 'lucide-react';
import { calendarioService } from './calendario.service';
import { CalendarEvent, EVENT_COLORS } from './calendario.types';
import EventModal from './components/EventModal';

const MONTHS = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const WEEKDAYS = ['D', 'S', 'T', 'Q', 'Q', 'S', 'S'];

const CalendarioPage: React.FC = () => {
  const [currentYear, setCurrentYear] = useState(new Date().getFullYear());
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    loadEvents();
  }, []);

  const loadEvents = async () => {
    const data = await calendarioService.getEvents();
    setEvents(data);
  };

  const handleAddEvent = async (event: any) => {
    await calendarioService.addEvent(event);
    loadEvents();
  };

  const handleDeleteEvent = async (id: string) => {
    await calendarioService.deleteEvent(id);
    loadEvents();
  };

  // Navegação de Ano
  const prevYear = () => setCurrentYear(prev => prev - 1);
  const nextYear = () => setCurrentYear(prev => prev + 1);
  const goToCurrentYear = () => setCurrentYear(new Date().getFullYear());

  // Utilitário para pegar dias do mês
  const getDaysInMonth = (year: number, monthIndex: number) => {
    const daysInMonth = new Date(year, monthIndex + 1, 0).getDate();
    const firstDayOfWeek = new Date(year, monthIndex, 1).getDay();

    const days = [];
    // Padding inicial
    for (let i = 0; i < firstDayOfWeek; i++) days.push(null);
    // Dias reais
    for (let i = 1; i <= daysInMonth; i++) days.push(new Date(year, monthIndex, i));

    return days;
  };

  const getEventsForDay = (date: Date) => {
    const dateStr = date.toISOString().split('T')[0];
    return events.filter(e => e.date === dateStr);
  };

  const handleDayClick = (date: Date) => {
    setSelectedDate(date);
    setIsModalOpen(true);
  };

  return (
    <div className="max-w-7xl mx-auto animate-fadeIn min-h-screen pb-10">

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-6">
        <div>
          <h2 className="text-3xl font-black text-[#001a33] uppercase tracking-tight flex items-center gap-3">
            <CalendarIcon className="text-blue-600" size={32} />
            Calendário {currentYear}
          </h2>
          <p className="text-slate-500 font-medium mt-1">Planejamento anual institucional e pedagógico.</p>
        </div>

        <div className="flex items-center gap-4 bg-white p-2 rounded-2xl shadow-sm border border-slate-100">
          <button onClick={prevYear} className="p-3 hover:bg-slate-50 rounded-xl text-slate-500 hover:text-[#001a33] transition-colors">
            <ChevronLeft size={20} />
          </button>
          <div className="text-center min-w-[100px]">
            <h3 className="text-2xl font-black text-[#001a33] tracking-tight">{currentYear}</h3>
          </div>
          <button onClick={nextYear} className="p-3 hover:bg-slate-50 rounded-xl text-slate-500 hover:text-[#001a33] transition-colors">
            <ChevronRight size={20} />
          </button>
          <div className="w-px h-8 bg-slate-200 mx-2"></div>
          <button onClick={goToCurrentYear} className="px-4 py-2 bg-slate-100 text-slate-600 text-xs font-bold uppercase tracking-wider rounded-xl hover:bg-slate-200 transition-colors">
            Ano Atual
          </button>
        </div>
      </div>

      {/* Legenda */}
      <div className="flex flex-wrap gap-4 mb-8 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm justify-center md:justify-start">
        <span className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2 mr-2">
            <Filter size={14} /> Legenda:
        </span>
        {Object.values(EVENT_COLORS).map((ec, idx) => (
          <div key={idx} className="flex items-center gap-2">
            <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: ec.color }}></div>
            <span className="text-[10px] font-bold text-slate-600 uppercase tracking-wide">{ec.label}</span>
          </div>
        ))}
      </div>

      {/* Grid de Meses (12 Meses) */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {MONTHS.map((monthName, monthIndex) => {
            const days = getDaysInMonth(currentYear, monthIndex);
            const isCurrentMonth = new Date().getMonth() === monthIndex && new Date().getFullYear() === currentYear;

            return (
                <div key={monthName} className={`bg-white rounded-3xl border p-5 transition-all hover:shadow-lg ${isCurrentMonth ? 'border-blue-200 shadow-blue-900/5 ring-1 ring-blue-100' : 'border-slate-100 shadow-sm'}`}>
                    {/* Nome do Mês */}
                    <h3 className={`text-lg font-black mb-4 uppercase tracking-wide text-center ${isCurrentMonth ? 'text-blue-600' : 'text-[#001a33]'}`}>
                        {monthName}
                    </h3>

                    {/* Cabeçalho Dias da Semana */}
                    <div className="grid grid-cols-7 mb-2">
                        {WEEKDAYS.map((day, i) => (
                            <div key={i} className="text-center text-[10px] font-bold text-slate-400">
                                {day}
                            </div>
                        ))}
                    </div>

                    {/* Dias */}
                    <div className="grid grid-cols-7 gap-y-2">
                        {days.map((date, dayIdx) => {
                            if (!date) return <div key={`empty-${dayIdx}`} className="h-8"></div>;

                            const dayEvents = getEventsForDay(date);
                            const hasEvents = dayEvents.length > 0;
                            const isToday = new Date().toDateString() === date.toDateString();

                            return (
                                <div 
                                    key={dayIdx} 
                                    onClick={() => handleDayClick(date)}
                                    className="flex flex-col items-center justify-start h-10 cursor-pointer group relative"
                                >
                                    <span className={`w-7 h-7 flex items-center justify-center rounded-full text-xs font-bold transition-colors ${
                                        isToday 
                                        ? 'bg-blue-600 text-white' 
                                        : hasEvents 
                                            ? 'text-[#001a33] font-black' 
                                            : 'text-slate-500 group-hover:bg-slate-100'
                                    }`}>
                                        {date.getDate()}
                                    </span>

                                    {/* Indicadores de Eventos (Dots) */}
                                    <div className="flex gap-0.5 mt-0.5">
                                        {dayEvents.slice(0, 3).map((ev, i) => (
                                            <div 
                                                key={i} 
                                                className="w-1 h-1 rounded-full" 
                                                style={{ backgroundColor: ev.color }} 
                                            />
                                        ))}
                                        {dayEvents.length > 3 && (
                                            <div className="w-1 h-1 rounded-full bg-slate-300" />
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            );
        })}
      </div>

      {selectedDate && (
        <EventModal 
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          selectedDate={selectedDate}
          eventsOnDate={getEventsForDay(selectedDate)}
          onAddEvent={handleAddEvent}
          onDeleteEvent={handleDeleteEvent}
        />
      )}

    </div>
  );
};

export default CalendarioPage;

