                    type="text" 
                    placeholder="Nome (ex: Reunião)"
                    className="flex-1 px-3 py-2 rounded-lg border border-slate-200 text-sm outline-none focus:border-blue-500"
                    value={newLabel}
                    onChange={(e) => setNewLabel(e.target.value)}
                />
                <div className="w-10 h-10 rounded-lg shrink-0 border border-slate-200 overflow-hidden relative">
                    <input 
                        type="color" 
