            <button 
                onClick={handleAdd}
                disabled={!newLabel}
                className="w-full py-2 bg-blue-600 text-white rounded-lg text-xs font-bold uppercase tracking-wider hover:bg-blue-700 transition-colors disabled:opacity-50"
