import React, { useState, useRef, useEffect } from 'react';
import { 
  CreditCard, Save, Upload, Plus, Move, Trash2, 
  Ruler, Hash, Image as ImageIcon, Eye, Layers, QrCode, CalendarClock
} from 'lucide-react';
import { carteirinhaService } from './carteirinha.service';

// Conversão aproximada: 1cm ~= 37.8px (96 DPI)
const PX_PER_CM = 37.8;

interface CardField {
  id: string;
  type: 'text' | 'image' | 'qrcode';
  label: string;
  x: number;
  y: number;
  width: number;
  height: number;
  fontSize?: number;
  color?: string;
  sampleValue: string; // Valor de exemplo para visualização
  side: 'frente' | 'verso';
}

const AVAILABLE_FIELDS = [
  { id: 'nome_aluno', label: 'Nome do Aluno', type: 'text', sampleValue: 'Ana Clara Souza' },
  { id: 'matricula', label: 'Matrícula', type: 'text', sampleValue: '202400158' },
  { id: 'rg', label: 'RG', type: 'text', sampleValue: '00.000.000-0' },
  { id: 'curso', label: 'Curso', type: 'text', sampleValue: 'Técnico em Enfermagem' },
  // Alterado para refletir a lógica de negócio (Fim da Turma)
  { id: 'validade', label: 'Validade (Fim da Turma)', type: 'text', sampleValue: '31/12/2025' }, 
  { id: 'foto_aluno', label: 'Foto 3x4', type: 'image', sampleValue: '', width: 75, height: 100 },
  { id: 'qrcode', label: 'QR Code Validação', type: 'qrcode', sampleValue: 'https://universo.com/validar/123', width: 80, height: 80 },
  { id: 'sequencial', label: 'Nº Carteirinha', type: 'text', sampleValue: '000501' },
];

const CarteirinhaPage: React.FC = () => {
  const [targetSide, setTargetSide] = useState<'frente' | 'verso'>('frente');
  const [loading, setLoading] = useState(false);

  // Configurações Gerais
  const [config, setConfig] = useState({
    widthCm: 8.5,
    heightCm: 5.5,
    startNumber: 1000,
    bgFrente: null as string | null,
    bgVerso: null as string | null
  });

  // Campos adicionados ao canvas
  const [fields, setFields] = useState<CardField[]>([]);

  // Controle de Drag
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  // Refs para os containers (Frente e Verso)
  const frenteRef = useRef<HTMLDivElement>(null);
  const versoRef = useRef<HTMLDivElement>(null);

  // Carregar dados iniciais
  useEffect(() => {
    loadTemplate();
  }, []);

  const loadTemplate = async () => {
    setLoading(true);
    const data = await carteirinhaService.getTemplate();
    if (data) {
      setConfig({
        widthCm: data.widthCm,
        heightCm: data.heightCm,
        startNumber: data.startNumber,
        bgFrente: data.bgFrente,
        bgVerso: data.bgVerso
      });
      setFields(data.fields || []);
    }
    setLoading(false);
  };

  // --- Handlers de Arquivo ---
  const handleBgUpload = (e: React.ChangeEvent<HTMLInputElement>, side: 'frente' | 'verso') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, [side === 'frente' ? 'bgFrente' : 'bgVerso']: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  // --- Handlers de Campos ---
  const addField = (fieldTemplate: any) => {
    const newField: CardField = {
      id: Math.random().toString(36).substr(2, 9),
      type: fieldTemplate.type as any,
      label: fieldTemplate.label,
      x: 10,
      y: 10,
      width: fieldTemplate.width || 150,
      height: fieldTemplate.height || 20,
      fontSize: 12,
      color: '#000000',
      sampleValue: fieldTemplate.sampleValue,
      side: targetSide // Adiciona no lado selecionado
    };
    setFields([...fields, newField]);
  };

  const removeField = (id: string) => {
    setFields(fields.filter(f => f.id !== id));
  };

  // --- Lógica de Drag & Drop ---
  const handleMouseDown = (e: React.MouseEvent, field: CardField) => {
    e.stopPropagation(); // Evita conflitos
    setDraggingId(field.id);

    // Calcula offset do clique em relação ao elemento
    const rect = (e.target as HTMLElement).getBoundingClientRect();
    setDragOffset({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!draggingId) return;

    const draggingField = fields.find(f => f.id === draggingId);
    if (!draggingField) return;

    // Seleciona o container correto baseado no lado do campo
    const containerRef = draggingField.side === 'frente' ? frenteRef : versoRef;
    if (!containerRef.current) return;

    const containerRect = containerRef.current.getBoundingClientRect();

    // Nova posição relativa ao container
    let newX = e.clientX - containerRect.left - dragOffset.x;
    let newY = e.clientY - containerRect.top - dragOffset.y;

    setFields(prev => prev.map(f => {
      if (f.id === draggingId) {
        return { ...f, x: newX, y: newY };
      }
      return f;
    }));
  };

  const handleMouseUp = () => {
    setDraggingId(null);
  };

  const handleSave = async () => {
    setLoading(true);
    await carteirinhaService.saveTemplate({
      ...config,
      fields
    });
    setLoading(false);
    alert('Modelo de carteirinha salvo com sucesso!');
  };

  // Helper para renderizar os campos dentro do container
  const renderFields = (side: 'frente' | 'verso') => {
    return fields.filter(f => f.side === side).map(field => (
        <div
            key={field.id}
            onMouseDown={(e) => handleMouseDown(e, field)}
            className={`absolute cursor-move group hover:ring-2 hover:ring-blue-400 hover:bg-blue-50/20 transition-shadow ${draggingId === field.id ? 'opacity-80 ring-2 ring-blue-500 z-50' : 'z-10'}`}
            style={{
                left: field.x,
                top: field.y,
                width: field.type === 'image' || field.type === 'qrcode' ? `${field.width}px` : 'auto',
                height: field.type === 'image' || field.type === 'qrcode' ? `${field.height}px` : 'auto',
            }}
        >
            {/* Conteúdo do Campo */}
            {field.type === 'image' ? (
                <div className="w-full h-full bg-slate-200 border-2 border-dashed border-slate-400 flex items-center justify-center text-slate-500 text-[10px] font-bold uppercase">
                    <ImageIcon size={16} className="mr-1" /> Foto
                </div>
            ) : field.type === 'qrcode' ? (
                // Renderiza QR Code Real para visualização (usando API pública para preview)
                <img 
                    src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${encodeURIComponent('VALIDACAO-ALUNO-MOCK')}`}
                    alt="QR Code"
                    className="w-full h-full object-contain pointer-events-none"
                />
            ) : (
                <div 
                    className="whitespace-nowrap px-1"
                    style={{ fontSize: `${field.fontSize || 12}px`, color: field.color, fontFamily: 'Arial, sans-serif', fontWeight: 'bold' }}
                >
                    {/* Badge visual para Validade Dinâmica */}
                    {field.label.includes('Validade') ? (
                        <span className="flex items-center gap-1">
                           {field.sampleValue}
                        </span>
                    ) : (
                        field.sampleValue
                    )}
                </div>
            )}

            {/* Botão de Remover (Aparece no Hover) */}
            <button 
                onClick={(e) => { e.stopPropagation(); removeField(field.id); }}
                className="absolute -top-3 -right-3 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-sm hover:scale-110"
                title="Remover Campo"
            >
                <Trash2 size={10} />
            </button>

            {/* Indicador de Movimento */}
            <div className="absolute top-0 left-0 p-0.5 bg-blue-500 text-white opacity-0 group-hover:opacity-100 text-[8px]">
                <Move size={8} />
            </div>
        </div>
    ));
  };

  // Estilos dinâmicos do container
  const getContainerStyle = (side: 'frente' | 'verso') => ({
    width: `${config.widthCm * PX_PER_CM}px`,
    height: `${config.heightCm * PX_PER_CM}px`,
    backgroundImage: side === 'frente' && config.bgFrente ? `url(${config.bgFrente})` : side === 'verso' && config.bgVerso ? `url(${config.bgVerso})` : 'none',
    backgroundSize: 'cover',
    backgroundPosition: 'center',
  });

  return (
    <div 
        className="animate-fadeIn min-h-screen pb-20" 
        onMouseUp={handleMouseUp} 
        onMouseMove={handleMouseMove} // Captura movimento global para fluidez
    >

      {/* Header */}
      <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl">
            <CreditCard size={32} />
          </div>
          <div>
            <h3 className="text-2xl font-black text-[#001a33] uppercase tracking-tight">Editor de Carteirinha</h3>
            <p className="text-slate-500 text-sm">Arraste os elementos para posicionar no modelo.</p>
          </div>
        </div>
        <div className="flex gap-3">
            <button className="flex items-center gap-2 px-6 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold text-xs uppercase tracking-wider hover:bg-slate-200 transition-colors">
                <Eye size={16} /> Preview PDF
            </button>
            <button 
                onClick={handleSave}
                disabled={loading}
                className="flex items-center gap-2 px-6 py-3 bg-[#001a33] text-white rounded-xl font-bold text-xs uppercase tracking-wider hover:bg-blue-900 transition-colors shadow-lg"
            >
                <Save size={16} /> {loading ? 'Salvando...' : 'Salvar Modelo'}
            </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Painel Esquerdo: Configurações e Campos */}
        <div className="lg:col-span-4 space-y-6">

            {/* Dimensões e Sequência */}
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                <h4 className="text-sm font-black text-[#001a33] uppercase tracking-wider mb-4 flex items-center gap-2">
                    <Ruler size={16} className="text-blue-500" /> Configuração Física
                </h4>
                <div className="grid grid-cols-2 gap-4 mb-4">
                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase mb-1">Largura (cm)</label>
                        <input 
                            type="number" 
                            step="0.1"
                            value={config.widthCm}
                            onChange={(e) => setConfig({...config, widthCm: parseFloat(e.target.value)})}
                            className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500"
                        />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase mb-1">Altura (cm)</label>
                        <input 
                            type="number" 
                            step="0.1"
                            value={config.heightCm}
                            onChange={(e) => setConfig({...config, heightCm: parseFloat(e.target.value)})}
                            className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500"
                        />
                    </div>
                </div>
                <div>
                    <label className="text-xs font-bold text-slate-500 uppercase mb-1 flex items-center gap-2">
                        <Hash size={14} /> Número Inicial (Sequencial)
                    </label>
                    <input 
                        type="number" 
                        value={config.startNumber}
                        onChange={(e) => setConfig({...config, startNumber: parseInt(e.target.value)})}
                        className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500"
                    />
                    <p className="text-[10px] text-slate-400 mt-1">Útil para continuar a numeração de carteirinhas já impressas.</p>
                </div>
            </div>

            {/* Uploads de Fundo */}
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                <h4 className="text-sm font-black text-[#001a33] uppercase tracking-wider mb-4 flex items-center gap-2">
                    <ImageIcon size={16} className="text-blue-500" /> Imagens de Fundo
                </h4>
                <div className="space-y-4">
                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase mb-2 block">Fundo Frente</label>
                        <div className="relative group cursor-pointer border-2 border-dashed border-slate-200 rounded-xl hover:bg-slate-50 hover:border-blue-300 transition-colors">
                            <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleBgUpload(e, 'frente')} />
                            <div className="p-4 flex items-center justify-center gap-3">
                                {config.bgFrente ? (
                                    <img src={config.bgFrente} alt="Frente" className="h-10 w-16 object-cover rounded shadow-sm" />
                                ) : (
                                    <Upload size={20} className="text-slate-400" />
                                )}
                                <span className="text-xs font-bold text-slate-600">
                                    {config.bgFrente ? 'Trocar Imagem' : 'Enviar Imagem'}
                                </span>
                            </div>
                        </div>
                    </div>
                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase mb-2 block">Fundo Verso</label>
                        <div className="relative group cursor-pointer border-2 border-dashed border-slate-200 rounded-xl hover:bg-slate-50 hover:border-blue-300 transition-colors">
                            <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleBgUpload(e, 'verso')} />
                            <div className="p-4 flex items-center justify-center gap-3">
                                {config.bgVerso ? (
                                    <img src={config.bgVerso} alt="Verso" className="h-10 w-16 object-cover rounded shadow-sm" />
                                ) : (
                                    <Upload size={20} className="text-slate-400" />
                                )}
                                <span className="text-xs font-bold text-slate-600">
                                    {config.bgVerso ? 'Trocar Imagem' : 'Enviar Imagem'}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Biblioteca de Campos */}
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                <h4 className="text-sm font-black text-[#001a33] uppercase tracking-wider mb-4 flex items-center gap-2">
                    <Plus size={16} className="text-blue-500" /> Adicionar Campos
                </h4>

                {/* Seletor de Destino */}
                <div className="flex bg-slate-50 p-1 rounded-xl mb-4 border border-slate-200">
                    <button 
                        onClick={() => setTargetSide('frente')}
                        className={`flex-1 py-2 text-[10px] font-bold uppercase rounded-lg transition-all ${targetSide === 'frente' ? 'bg-white shadow text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                        Na Frente
                    </button>
                    <button 
                        onClick={() => setTargetSide('verso')}
                        className={`flex-1 py-2 text-[10px] font-bold uppercase rounded-lg transition-all ${targetSide === 'verso' ? 'bg-white shadow text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                        No Verso
                    </button>
                </div>

                <div className="flex flex-wrap gap-2">
                    {AVAILABLE_FIELDS.map(field => (
                        <button 
                            key={field.id}
                            onClick={() => addField(field)}
                            className="px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs font-bold text-slate-600 hover:bg-blue-50 hover:text-blue-600 hover:border-blue-200 transition-all flex items-center gap-2"
                        >
                            <Plus size={12} /> 
                            {field.id === 'qrcode' && <QrCode size={12} />}
                            {field.label}
                        </button>
                    ))}
                </div>

                <div className="mt-4 p-3 bg-blue-50 rounded-xl border border-blue-100">
                    <p className="text-[10px] text-blue-700 leading-snug flex items-start gap-2">
                        <CalendarClock size={14} className="shrink-0 mt-0.5" />
                        <span>
                            <b>Atenção:</b> O campo "Validade" é dinâmico e será preenchido automaticamente com a <span className="underline decoration-blue-400">Data Final da Turma</span> vinculada ao aluno.
                        </span>
                    </p>
                </div>
            </div>

        </div>

        {/* Painel Central: Canvas Editor (Visualização Dupla) */}
        <div className="lg:col-span-8 flex flex-col items-center gap-8 bg-slate-200/50 p-8 rounded-[3rem] border border-slate-300/50 shadow-inner overflow-y-auto max-h-[calc(100vh-150px)] custom-scrollbar">

            {/* --- CARTÃO FRENTE --- */}
            <div className="flex flex-col items-center">
                <div className="flex items-center gap-2 mb-3 text-slate-400">
                    <Layers size={14} />
                    <span className="text-xs font-black uppercase tracking-[0.2em]">Frente do Cartão</span>
                </div>

                <div 
                    ref={frenteRef}
                    className="relative bg-white shadow-xl transition-all select-none overflow-hidden hover:shadow-2xl ring-1 ring-slate-200"
                    style={getContainerStyle('frente')}
                >
                    {renderFields('frente')}

                    {!config.bgFrente && (
                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                            <p className="text-slate-300 font-bold text-lg uppercase tracking-widest rotate-[-15deg] border-2 border-slate-300 p-2 rounded-xl border-dashed">
                                Fundo Frente
                            </p>
                        </div>
                    )}
                </div>
            </div>

            {/* Divisor Visual */}
            <div className="w-12 h-1 bg-slate-300 rounded-full"></div>

            {/* --- CARTÃO VERSO --- */}
            <div className="flex flex-col items-center pb-8">
                <div className="flex items-center gap-2 mb-3 text-slate-400">
                    <Layers size={14} />
                    <span className="text-xs font-black uppercase tracking-[0.2em]">Verso do Cartão</span>
                </div>

                <div 
                    ref={versoRef}
                    className="relative bg-white shadow-xl transition-all select-none overflow-hidden hover:shadow-2xl ring-1 ring-slate-200"
                    style={getContainerStyle('verso')}
                >
                    {renderFields('verso')}

                    {!config.bgVerso && (
                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                            <p className="text-slate-300 font-bold text-lg uppercase tracking-widest rotate-[-15deg] border-2 border-slate-300 p-2 rounded-xl border-dashed">
                                Fundo Verso
                            </p>
                        </div>
                    )}
                </div>
            </div>

            {/* Régua Info */}
            <div className="fixed bottom-8 right-12 bg-white/80 backdrop-blur px-4 py-2 rounded-xl shadow-lg border border-slate-200 text-xs font-mono text-slate-500 pointer-events-none">
                Dimensões: {config.widthCm}cm x {config.heightCm}cm
            </div>

        </div>

      </div>
    </div>
  );
};

export default CarteirinhaPage;

import React, { useState, useRef, useEffect } from 'react';
import { 
  CreditCard, Save, Upload, Plus, Move, Trash2, 
  Ruler, Hash, Image as ImageIcon, Eye, Layers, QrCode, CalendarClock, Settings2, Type
} from 'lucide-react';
import { carteirinhaService } from './carteirinha.service';

// Conversão aproximada: 1cm ~= 37.8px (96 DPI)
const PX_PER_CM = 37.8;

interface CardField {
  id: string;
  type: 'text' | 'image' | 'qrcode';
  label: string;
  x: number;
  y: number;
  width: number;
  height: number;
  fontSize?: number;
  color?: string;
  sampleValue: string; // Valor de exemplo para visualização
  side: 'frente' | 'verso';
}

const AVAILABLE_FIELDS = [
  { id: 'nome_aluno', label: 'Nome do Aluno', type: 'text', sampleValue: 'Ana Clara Souza' },
  { id: 'matricula', label: 'Matrícula', type: 'text', sampleValue: '202400158' },
  { id: 'rg', label: 'RG', type: 'text', sampleValue: '00.000.000-0' }, // RG Típico
  { id: 'cpf', label: 'CPF', type: 'text', sampleValue: '000.000.000-00' }, // CPF Típico
  { id: 'curso', label: 'Curso', type: 'text', sampleValue: 'Técnico em Enfermagem' },
  { id: 'validade', label: 'Validade (Fim da Turma)', type: 'text', sampleValue: '31/12/2025' }, 
  { id: 'foto_aluno', label: 'Foto 3x4', type: 'image', sampleValue: '', width: 75, height: 100 },
  { id: 'qrcode', label: 'QR Code Validação', type: 'qrcode', sampleValue: 'https://universo.com/validar/123', width: 80, height: 80 },
  { id: 'sequencial', label: 'Nº Carteirinha', type: 'text', sampleValue: '000501' },
];

const CarteirinhaPage: React.FC = () => {
  const [targetSide, setTargetSide] = useState<'frente' | 'verso'>('frente');
  const [loading, setLoading] = useState(false);

  // Configurações Gerais
  const [config, setConfig] = useState({
    widthCm: 8.5,
    heightCm: 5.5,
    startNumber: 1000,
    bgFrente: null as string | null,
    bgVerso: null as string | null
  });

  // Campos adicionados ao canvas
  const [fields, setFields] = useState<CardField[]>([]);

  // Controle de Drag e Seleção
  const [selectedFieldId, setSelectedFieldId] = useState<string | null>(null);
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  // Refs para os containers (Frente e Verso)
  const frenteRef = useRef<HTMLDivElement>(null);
  const versoRef = useRef<HTMLDivElement>(null);

  // Carregar dados iniciais
  useEffect(() => {
    loadTemplate();
  }, []);

  const loadTemplate = async () => {
    setLoading(true);
    const data = await carteirinhaService.getTemplate();
    if (data) {
      setConfig({
        widthCm: data.widthCm,
        heightCm: data.heightCm,
        startNumber: data.startNumber,
        bgFrente: data.bgFrente,
        bgVerso: data.bgVerso
      });
      setFields(data.fields || []);
    }
    setLoading(false);
  };

  // --- Handlers de Arquivo ---
  const handleBgUpload = (e: React.ChangeEvent<HTMLInputElement>, side: 'frente' | 'verso') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, [side === 'frente' ? 'bgFrente' : 'bgVerso']: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  // --- Handlers de Campos ---
  const addField = (fieldTemplate: any) => {
    const newField: CardField = {
      id: Math.random().toString(36).substr(2, 9),
      type: fieldTemplate.type as any,
      label: fieldTemplate.label,
      x: 10,
      y: 10,
      width: fieldTemplate.width || 150,
      height: fieldTemplate.height || 20,
      fontSize: 12,
      color: '#000000',
      sampleValue: fieldTemplate.sampleValue,
      side: targetSide
    };
    setFields([...fields, newField]);
    setSelectedFieldId(newField.id); // Seleciona automaticamente o novo campo
  };

  const removeField = (id: string) => {
    setFields(fields.filter(f => f.id !== id));
    if (selectedFieldId === id) setSelectedFieldId(null);
  };

  const updateField = (id: string, updates: Partial<CardField>) => {
    setFields(prev => prev.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  // --- Lógica de Drag & Drop ---
  const handleMouseDown = (e: React.MouseEvent, field: CardField) => {
    e.stopPropagation();
    setSelectedFieldId(field.id);
    setDraggingId(field.id);

    const rect = (e.target as HTMLElement).getBoundingClientRect();
    setDragOffset({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!draggingId) return;

    const draggingField = fields.find(f => f.id === draggingId);
    if (!draggingField) return;

    const containerRef = draggingField.side === 'frente' ? frenteRef : versoRef;
    if (!containerRef.current) return;

    const containerRect = containerRef.current.getBoundingClientRect();

    let newX = e.clientX - containerRect.left - dragOffset.x;
    let newY = e.clientY - containerRect.top - dragOffset.y;

    setFields(prev => prev.map(f => {
      if (f.id === draggingId) {
        return { ...f, x: newX, y: newY };
      }
      return f;
    }));
  };

  const handleMouseUp = () => {
    setDraggingId(null);
  };

  const handleSave = async () => {
    setLoading(true);
    await carteirinhaService.saveTemplate({
      ...config,
      fields
    });
    setLoading(false);
    alert('Modelo de carteirinha salvo com sucesso!');
  };

  // --- Renderização do Painel de Propriedades ---
  const renderPropertiesPanel = () => {
    const field = fields.find(f => f.id === selectedFieldId);
    if (!field) return null;

    return (
        <div className="bg-blue-50/50 p-6 rounded-[2rem] border border-blue-100 shadow-sm animate-fadeIn mb-6">
            <h4 className="text-sm font-black text-[#001a33] uppercase tracking-wider mb-4 flex items-center gap-2">
                <Settings2 size={16} className="text-blue-600" /> Propriedades: <span className="text-blue-600">{field.label}</span>
            </h4>

            <div className="grid grid-cols-2 gap-4 mb-4">
                <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Posição X</label>
                    <input 
                        type="number" 
                        value={Math.round(field.x)}
                        onChange={(e) => updateField(field.id, { x: parseInt(e.target.value) })}
                        className="w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500 text-xs"
                    />
                </div>
                <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Posição Y</label>
                    <input 
                        type="number" 
                        value={Math.round(field.y)}
                        onChange={(e) => updateField(field.id, { y: parseInt(e.target.value) })}
                        className="w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500 text-xs"
                    />
                </div>
            </div>

            {/* Propriedades Específicas de Texto */}
            {field.type === 'text' && (
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 flex items-center gap-1">
                            <Type size={10} /> Tam. Fonte (px)
                        </label>
                        <input 
                            type="number" 
                            value={field.fontSize}
                            onChange={(e) => updateField(field.id, { fontSize: parseInt(e.target.value) })}
                            className="w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500 text-xs"
                        />
                    </div>
                    <div>
                        <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Cor do Texto</label>
                        <div className="flex gap-2 items-center">
                            <input 
                                type="color" 
                                value={field.color}
                                onChange={(e) => updateField(field.id, { color: e.target.value })}
                                className="w-8 h-8 rounded-lg border-none cursor-pointer"
                            />
                            <span className="text-xs font-mono text-slate-500">{field.color}</span>
                        </div>
                    </div>
                </div>
            )}

            {/* Propriedades Específicas de Imagem/QR */}
            {(field.type === 'image' || field.type === 'qrcode') && (
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Largura (px)</label>
                        <input 
                            type="number" 
                            value={field.width}
                            onChange={(e) => updateField(field.id, { width: parseInt(e.target.value) })}
                            className="w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500 text-xs"
                        />
                    </div>
                    <div>
                        <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Altura (px)</label>
                        <input 
                            type="number" 
                            value={field.height}
                            onChange={(e) => updateField(field.id, { height: parseInt(e.target.value) })}
                            className="w-full px-3 py-2 bg-white border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500 text-xs"
                        />
                    </div>
                </div>
            )}

            <button 
                onClick={() => removeField(field.id)}
                className="w-full mt-4 flex items-center justify-center gap-2 py-2 bg-red-50 text-red-600 rounded-lg text-xs font-bold uppercase hover:bg-red-100 transition-colors"
            >
                <Trash2 size={14} /> Remover Item
            </button>
        </div>
    );
  };

  const renderFields = (side: 'frente' | 'verso') => {
    return fields.filter(f => f.side === side).map(field => {
        const isSelected = selectedFieldId === field.id;
        return (
            <div
                key={field.id}
                onMouseDown={(e) => handleMouseDown(e, field)}
                className={`absolute cursor-move group transition-all ${
                    isSelected ? 'ring-2 ring-blue-500 z-50' : 'z-10 hover:ring-1 hover:ring-blue-300'
                }`}
                style={{
                    left: field.x,
                    top: field.y,
                    width: field.type === 'image' || field.type === 'qrcode' ? `${field.width}px` : 'auto',
                    height: field.type === 'image' || field.type === 'qrcode' ? `${field.height}px` : 'auto',
                }}
            >
                {/* Conteúdo do Campo */}
                {field.type === 'image' ? (
                    <div className="w-full h-full bg-slate-200/50 border-2 border-dashed border-slate-400 flex items-center justify-center text-slate-500 text-[10px] font-bold uppercase backdrop-blur-sm">
                        <ImageIcon size={16} className="mr-1" /> Foto
                    </div>
                ) : field.type === 'qrcode' ? (
                    <img 
                        src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${encodeURIComponent('VALIDACAO-ALUNO-MOCK')}`}
                        alt="QR Code"
                        className="w-full h-full object-contain pointer-events-none"
                    />
                ) : (
                    <div 
                        className="whitespace-nowrap px-1 select-none"
                        style={{ fontSize: `${field.fontSize || 12}px`, color: field.color, fontFamily: 'Arial, sans-serif', fontWeight: 'bold' }}
                    >
                        {field.label.includes('Validade') ? (
                            <span className="flex items-center gap-1">
                               {field.sampleValue}
                            </span>
                        ) : (
                            field.sampleValue
                        )}
                    </div>
                )}

                {/* Indicadores Visuais de Seleção */}
                {isSelected && (
                    <>
                        <div className="absolute -top-1 -left-1 w-2 h-2 bg-blue-500 rounded-full"></div>
                        <div className="absolute -top-1 -right-1 w-2 h-2 bg-blue-500 rounded-full"></div>
                        <div className="absolute -bottom-1 -left-1 w-2 h-2 bg-blue-500 rounded-full"></div>
                        <div className="absolute -bottom-1 -right-1 w-2 h-2 bg-blue-500 rounded-full"></div>
                    </>
                )}
            </div>
        );
    });
  };

  const getContainerStyle = (side: 'frente' | 'verso') => ({
    width: `${config.widthCm * PX_PER_CM}px`,
    height: `${config.heightCm * PX_PER_CM}px`,
    backgroundImage: side === 'frente' && config.bgFrente ? `url(${config.bgFrente})` : side === 'verso' && config.bgVerso ? `url(${config.bgVerso})` : 'none',
    backgroundSize: 'cover',
    backgroundPosition: 'center',
  });

  return (
    <div 
        className="animate-fadeIn min-h-screen pb-20" 
        onMouseUp={handleMouseUp} 
        onMouseMove={handleMouseMove}
    >

      <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl">
            <CreditCard size={32} />
          </div>
          <div>
            <h3 className="text-2xl font-black text-[#001a33] uppercase tracking-tight">Editor de Carteirinha</h3>
            <p className="text-slate-500 text-sm">Personalize o layout e as dimensões dos elementos.</p>
          </div>
        </div>
        <div className="flex gap-3">
            <button className="flex items-center gap-2 px-6 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold text-xs uppercase tracking-wider hover:bg-slate-200 transition-colors">
                <Eye size={16} /> Preview PDF
            </button>
            <button 
                onClick={handleSave}
                disabled={loading}
                className="flex items-center gap-2 px-6 py-3 bg-[#001a33] text-white rounded-xl font-bold text-xs uppercase tracking-wider hover:bg-blue-900 transition-colors shadow-lg"
            >
                <Save size={16} /> {loading ? 'Salvando...' : 'Salvar Modelo'}
            </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Painel Esquerdo: Configurações, Propriedades e Campos */}
        <div className="lg:col-span-4 space-y-6">

            {/* 1. Painel de Propriedades (Só aparece se algo estiver selecionado) */}
            {selectedFieldId ? renderPropertiesPanel() : (
                <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-200 border-dashed text-center">
                    <p className="text-slate-400 text-sm font-medium">Selecione um elemento na carteirinha para editar suas propriedades (tamanho, cor, posição).</p>
                </div>
            )}

            {/* 2. Dimensões e Sequência */}
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                <h4 className="text-sm font-black text-[#001a33] uppercase tracking-wider mb-4 flex items-center gap-2">
                    <Ruler size={16} className="text-blue-500" /> Configuração Física
                </h4>
                <div className="grid grid-cols-2 gap-4 mb-4">
                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase mb-1">Largura (cm)</label>
                        <input 
                            type="number" 
                            step="0.1"
                            value={config.widthCm}
                            onChange={(e) => setConfig({...config, widthCm: parseFloat(e.target.value)})}
                            className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500"
                        />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase mb-1">Altura (cm)</label>
                        <input 
                            type="number" 
                            step="0.1"
                            value={config.heightCm}
                            onChange={(e) => setConfig({...config, heightCm: parseFloat(e.target.value)})}
                            className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500"
                        />
                    </div>
                </div>
                <div>
                    <label className="text-xs font-bold text-slate-500 uppercase mb-1 flex items-center gap-2">
                        <Hash size={14} /> Número Inicial (Sequencial)
                    </label>
                    <input 
                        type="number" 
                        value={config.startNumber}
                        onChange={(e) => setConfig({...config, startNumber: parseInt(e.target.value)})}
                        className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-slate-700 outline-none focus:border-blue-500"
                    />
                </div>
            </div>

            {/* 3. Uploads de Fundo */}
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                <h4 className="text-sm font-black text-[#001a33] uppercase tracking-wider mb-4 flex items-center gap-2">
                    <ImageIcon size={16} className="text-blue-500" /> Imagens de Fundo
                </h4>
                <div className="space-y-4">
                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase mb-2 block">Fundo Frente</label>
                        <div className="relative group cursor-pointer border-2 border-dashed border-slate-200 rounded-xl hover:bg-slate-50 hover:border-blue-300 transition-colors">
                            <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleBgUpload(e, 'frente')} />
                            <div className="p-4 flex items-center justify-center gap-3">
                                {config.bgFrente ? (
                                    <img src={config.bgFrente} alt="Frente" className="h-10 w-16 object-cover rounded shadow-sm" />
                                ) : (
                                    <Upload size={20} className="text-slate-400" />
                                )}
                                <span className="text-xs font-bold text-slate-600">
                                    {config.bgFrente ? 'Trocar Imagem' : 'Enviar Imagem'}
                                </span>
                            </div>
                        </div>
                    </div>
                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase mb-2 block">Fundo Verso</label>
                        <div className="relative group cursor-pointer border-2 border-dashed border-slate-200 rounded-xl hover:bg-slate-50 hover:border-blue-300 transition-colors">
                            <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleBgUpload(e, 'verso')} />
                            <div className="p-4 flex items-center justify-center gap-3">
                                {config.bgVerso ? (
                                    <img src={config.bgVerso} alt="Verso" className="h-10 w-16 object-cover rounded shadow-sm" />
                                ) : (
                                    <Upload size={20} className="text-slate-400" />
                                )}
                                <span className="text-xs font-bold text-slate-600">
                                    {config.bgVerso ? 'Trocar Imagem' : 'Enviar Imagem'}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* 4. Biblioteca de Campos */}
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                <h4 className="text-sm font-black text-[#001a33] uppercase tracking-wider mb-4 flex items-center gap-2">
                    <Plus size={16} className="text-blue-500" /> Adicionar Campos
                </h4>

                <div className="flex bg-slate-50 p-1 rounded-xl mb-4 border border-slate-200">
                    <button 
                        onClick={() => setTargetSide('frente')}
                        className={`flex-1 py-2 text-[10px] font-bold uppercase rounded-lg transition-all ${targetSide === 'frente' ? 'bg-white shadow text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                        Na Frente
                    </button>
                    <button 
                        onClick={() => setTargetSide('verso')}
                        className={`flex-1 py-2 text-[10px] font-bold uppercase rounded-lg transition-all ${targetSide === 'verso' ? 'bg-white shadow text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
