import { supabase } from '../../../../../../lib/supabase';

// Mock Storage para os Templates
// Chave: `cursoId`
let templatesStore: Record<string, any> = {};

// Configurações Globais (Ex: Sequencial)
let globalSettings = {
  proximoNumeroSequencial: 1000,
  prefixoGeral: '2024'
};

// Template Padrão (Fallback)
const defaultTemplate = {
  widthCm: 8.5,
  heightCm: 5.5,
  bgFrente: null,
  bgVerso: null,
  fields: []
};

export const carteirinhaService = {
  // --- Configurações Globais ---
  async getGlobalSettings() {
    return new Promise<typeof globalSettings>((resolve) => {
      setTimeout(() => resolve({ ...globalSettings }), 300);
    });
  },

  async saveGlobalSettings(settings: typeof globalSettings) {
    return new Promise<void>((resolve) => {
      setTimeout(() => {
        globalSettings = settings;
        resolve();
      }, 500);
    });
  },

  // --- Templates por Curso ---
  async getTemplate(cursoId: string) {
    // Simula delay de rede
    return new Promise<any>((resolve) => {
      setTimeout(() => {
        const template = templatesStore[cursoId] || { ...defaultTemplate }; 
        resolve(template);
      }, 500);
    });
  },

  async saveTemplate(cursoId: string, data: any) {
    // Simula salvamento
    return new Promise<boolean>((resolve) => {
      setTimeout(() => {
        templatesStore[cursoId] = data;
        resolve(true);
      }, 800);
    });
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  CreditCard, Save, Upload, Plus, Move, Trash2, 
  Ruler, Hash, Image as ImageIcon, Eye, Layers, QrCode, CalendarClock, Settings2, Type,
  Briefcase, Zap, Award, ArrowLeft, Search, Settings, CheckCircle2
} from 'lucide-react';
import { carteirinhaService } from './carteirinha.service';
import { cursosTecnicosService } from '../../cursos-tecnicos/cursos-tecnicos.service';
import { cursosLivresService } from '../../cursos-livres/cursos-livres.service';
import { cursosEspecializacaoService } from '../../cursos-especializacao/cursos-especializacao.service';

// Conversão aproximada: 1cm ~= 37.8px (96 DPI)
const PX_PER_CM = 37.8;

// Tipos
interface CardField {
  id: string;
  type: 'text' | 'image' | 'qrcode';
  label: string;
  x: number;
  y: number;
  width: number;
  height: number;
  fontSize?: number;
  color?: string;
  sampleValue: string;
  side: 'frente' | 'verso';
}

const AVAILABLE_FIELDS = [
  { id: 'nome_aluno', label: 'Nome do Aluno', type: 'text', sampleValue: 'Ana Clara Souza' },
  { id: 'matricula', label: 'Matrícula', type: 'text', sampleValue: '202400158' },
  { id: 'rg', label: 'RG', type: 'text', sampleValue: '00.000.000-0' },
  { id: 'cpf', label: 'CPF', type: 'text', sampleValue: '000.000.000-00' },
  { id: 'curso', label: 'Nome do Curso', type: 'text', sampleValue: 'Técnico em Enfermagem' },
  { id: 'validade', label: 'Validade (Fim da Turma)', type: 'text', sampleValue: '31/12/2025' }, 
  { id: 'foto_aluno', label: 'Foto 3x4', type: 'image', sampleValue: '', width: 75, height: 100 },
  { id: 'qrcode', label: 'QR Code Validação', type: 'qrcode', sampleValue: 'https://universo.com/validar/123', width: 80, height: 80 },
  { id: 'sequencial', label: 'Nº Carteirinha', type: 'text', sampleValue: '000501' },
];

const CarteirinhaPage: React.FC = () => {
  // --- Estados de Navegação e Dados ---
  const [step, setStep] = useState<'list' | 'edit'>('list');
  const [courses, setCourses] = useState<any[]>([]);
  const [selectedCourse, setSelectedCourse] = useState<any | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // --- Estados de Configuração Global ---
  const [globalSettings, setGlobalSettings] = useState({ proximoNumeroSequencial: 1000, prefixoGeral: '' });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  // --- Estados do Editor ---
  const [targetSide, setTargetSide] = useState<'frente' | 'verso'>('frente');
  const [loading, setLoading] = useState(false);
  const [config, setConfig] = useState({
    widthCm: 8.5,
    heightCm: 5.5,
    bgFrente: null as string | null,
    bgVerso: null as string | null
  });
  const [fields, setFields] = useState<CardField[]>([]);
  const [selectedFieldId, setSelectedFieldId] = useState<string | null>(null);
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const frenteRef = useRef<HTMLDivElement>(null);
  const versoRef = useRef<HTMLDivElement>(null);

  // Carregar Dados Iniciais
  useEffect(() => {
    loadInitialData();
  }, []);

  const loadInitialData = async () => {
    // 1. Carrega Configurações Globais
    const settings = await carteirinhaService.getGlobalSettings();
    setGlobalSettings(settings);

    // 2. Carrega e unifica todos os cursos
    const tecnicos = await cursosTecnicosService.getAll();
    const livres = await cursosLivresService.getAll();
    const especializacoes = await cursosEspecializacaoService.getAll();

    const allCourses = [
      ...tecnicos.map(c => ({ ...c, type: 'TECNICO', label: 'Técnico' })),
      ...livres.map(c => ({ ...c, type: 'LIVRE', label: 'Curso Livre' })),
      ...especializacoes.map(c => ({ ...c, type: 'ESPECIALIZACAO', label: 'Especialização' }))
    ];
    setCourses(allCourses);
  };

  const handleSaveGlobalSettings = async () => {
    setIsSavingSettings(true);
    await carteirinhaService.saveGlobalSettings(globalSettings);
    setIsSavingSettings(false);
    alert('Configurações globais atualizadas!');
  };

  // --- Fluxo de Seleção ---
  const handleSelectCourse = async (course: any) => {
    setSelectedCourse(course);
    setStep('edit');
    setLoading(true);

    // Carrega template específico do curso
    const data = await carteirinhaService.getTemplate(course.id);
    if (data) {
      setConfig({
        widthCm: data.widthCm,
        heightCm: data.heightCm,
        bgFrente: data.bgFrente,
        bgVerso: data.bgVerso
      });
      setFields(data.fields || []);
    } else {
        // Reset se não houver template
        setFields([]);
    }
    setLoading(false);
  };

  const filteredCourses = courses.filter(c => 
    c.nome.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Handlers do Editor ---
  const handleBgUpload = (e: React.ChangeEvent<HTMLInputElement>, side: 'frente' | 'verso') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setConfig(prev => ({ ...prev, [side === 'frente' ? 'bgFrente' : 'bgVerso']: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const addField = (fieldTemplate: any) => {
    const newField: CardField = {
      id: Math.random().toString(36).substr(2, 9),
      type: fieldTemplate.type as any,
      label: fieldTemplate.label,
      x: 10,
      y: 10,
      width: fieldTemplate.width || 150,
      height: fieldTemplate.height || 20,
      fontSize: 12,
      color: '#000000',
      sampleValue: fieldTemplate.sampleValue,
      side: targetSide
    };
    setFields([...fields, newField]);
    setSelectedFieldId(newField.id);
  };

  const removeField = (id: string) => {
    setFields(fields.filter(f => f.id !== id));
    if (selectedFieldId === id) setSelectedFieldId(null);
  };

  const updateField = (id: string, updates: Partial<CardField>) => {
    setFields(prev => prev.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  const handleMouseDown = (e: React.MouseEvent, field: CardField) => {
    e.stopPropagation();
    setSelectedFieldId(field.id);
    setDraggingId(field.id);

    const rect = (e.target as HTMLElement).getBoundingClientRect();
    setDragOffset({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!draggingId) return;

    const draggingField = fields.find(f => f.id === draggingId);
    if (!draggingField) return;

    const containerRef = draggingField.side === 'frente' ? frenteRef : versoRef;
    if (!containerRef.current) return;

    const containerRect = containerRef.current.getBoundingClientRect();

    let newX = e.clientX - containerRect.left - dragOffset.x;
    let newY = e.clientY - containerRect.top - dragOffset.y;

    setFields(prev => prev.map(f => {
      if (f.id === draggingId) {
        return { ...f, x: newX, y: newY };
      }
      return f;
    }));
  };

  const handleMouseUp = () => {
    setDraggingId(null);
  };

  const handleSaveTemplate = async () => {
    if (!selectedCourse) return;
    setLoading(true);
    await carteirinhaService.saveTemplate(selectedCourse.id, {
      ...config,
      fields
    });
    setLoading(false);
    alert(`Modelo para ${selectedCourse.nome} salvo com sucesso!`);
  };

  const getCourseIcon = (type: string) => {
    switch(type) {
        case 'TECNICO': return <Briefcase size={24} />;
        case 'LIVRE': return <Zap size={24} />;
        case 'ESPECIALIZACAO': return <Award size={24} />;
        default: return <CreditCard size={24} />;
    }
  };

  const getCourseColor = (type: string) => {
    switch(type) {
        case 'TECNICO': return 'text-emerald-600 bg-emerald-50 border-emerald-100';
        case 'LIVRE': return 'text-amber-600 bg-amber-50 border-amber-100';
        case 'ESPECIALIZACAO': return 'text-rose-600 bg-rose-50 border-rose-100';
        default: return 'text-blue-600 bg-blue-50 border-blue-100';
    }
  };

  // --- RENDERIZAÇÃO: LISTA DE CURSOS ---
  if (step === 'list') {
    return (
      <div className="animate-fadeIn max-w-7xl mx-auto">

        {/* Painel de Configuração Global */}
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm mb-10 flex flex-col md:flex-row items-center justify-between gap-6">
            <div className="flex items-center gap-4">
                <div className="p-4 bg-slate-50 text-slate-600 rounded-2xl border border-slate-200">
                    <Settings size={24} />
                </div>
                <div>
                    <h3 className="text-lg font-black text-[#001a33] uppercase tracking-tight">Configuração Global</h3>
                    <p className="text-slate-500 text-sm">Defina a sequência numérica para todas as carteirinhas.</p>
                </div>
            </div>

            <div className="flex items-end gap-4 bg-slate-50 p-4 rounded-2xl border border-slate-200">
                <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase block mb-1">Próximo Sequencial</label>
                    <div className="flex items-center gap-2">
                        <Hash size={16} className="text-slate-400" />
                        <input 
                            type="number" 
                            className="bg-white w-32 px-3 py-2 rounded-lg border border-slate-200 font-bold text-[#001a33] outline-none focus:border-blue-500"
                            value={globalSettings.proximoNumeroSequencial}
                            onChange={(e) => setGlobalSettings({...globalSettings, proximoNumeroSequencial: parseInt(e.target.value)})}
                        />
                    </div>
                </div>
                <button 
                    onClick={handleSaveGlobalSettings}
                    disabled={isSavingSettings}
                    className="h-10 px-4 bg-[#001a33] text-white rounded-lg font-bold uppercase text-xs hover:bg-blue-900 transition-colors flex items-center gap-2"
                >
                    {isSavingSettings ? '...' : <><Save size={14} /> Salvar</>}
                </button>
            </div>
        </div>

        {/* Header e Busca */}
        <div className="mb-8">
            <h2 className="text-2xl font-black text-[#001a33] uppercase tracking-tight mb-2">
                Definir Modelos por Curso
            </h2>
            <div className="relative max-w-md">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                <input 
                    type="text" 
                    placeholder="Buscar curso para editar modelo..." 
                    className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl outline-none focus:border-blue-500 font-medium"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>
        </div>

        {/* Grid de Cursos */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredCourses.map(course => (
                <button 
                    key={course.id}
                    onClick={() => handleSelectCourse(course)}
                    className="group bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:shadow-blue-900/10 hover:-translate-y-1 transition-all duration-300 text-left flex flex-col h-full relative overflow-hidden"
                >
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center mb-4 border transition-colors group-hover:scale-110 duration-300 ${getCourseColor(course.type)}`}>
