                    <div className="absolute -top-12 left-0 bg-white border border-slate-200 shadow-lg rounded-xl p-1 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none group-hover:pointer-events-auto z-50">
