                        <button onClick={() => handleFormat('justifyCenter')} className="p-2 hover:bg-slate-100 rounded-lg text-slate-600"><AlignCenter size={14} /></button>
                        <button onClick={() => handleFormat('justifyRight')} className="p-2 hover:bg-slate-100 rounded-lg text-slate-600"><AlignRight size={14} /></button>
                    </div>

                    <div 
