            width: 100,
            style: { zIndex: 50 }
        };
    } else {
        newField = {
            id: Math.random().toString(36).substr(2, 9),
            type: 'text',
            value: draggedItem.code,
            x: x - 50,
            y: y - 10,
            style: { fontWeight: 'bold', fontSize: '14px', color: '#000' }
