                            <span className="text-xs font-mono text-slate-500">{field.color}</span>
                        </div>
                    </div>
                </div>
            )}

            {/* Propriedades Específicas de Imagem/QR */}
            {(field.type === 'image' || field.type === 'qrcode') && (
