                    width: field.type === 'image' || field.type === 'qrcode' ? `${field.width}px` : 'auto',
                    height: field.type === 'image' || field.type === 'qrcode' ? `${field.height}px` : 'auto',
                }}
            >
                {/* Conteúdo do Campo */}
                {field.type === 'image' ? (
