                    />
                ) : (
                    <div 
                        className="whitespace-nowrap px-1 select-none"
                        style={{ fontSize: `${field.fontSize || 12}px`, color: field.color, fontFamily: 'Arial, sans-serif', fontWeight: 'bold' }}
